def eprint(*args, **kwargs):
    print(*args, file=sys.stderr, **kwargs)


def parse_kv_list(items: Optional[List[str]]) -> Dict[str, str]:
    cfg: Dict[str, str] = {}
    if not items:
        return cfg
    for item in items:
        if item is None:
            continue
        if "=" not in item:
            raise ValueError(f"Invalid key=value: {item}")
        k, v = item.split("=", 1)
        k = k.strip()
        v = v.strip()
        if not k:
            raise ValueError(f"Invalid key in key=value: {item}")
        cfg[k] = v
    return cfg


def parse_topic_list(s: Optional[str]) -> List[str]:
    if not s:
        return []
    parts = [p.strip() for p in s.split(",")]
    return [p for p in parts if p]


def parse_int_list(s: Optional[str]) -> List[int]:
    if not s:
        return []
    out: List[int] = []
    for p in s.split(","):
        p = p.strip()
        if not p:
            continue
        out.append(int(p))
    return out


def load_json_file(path: str) -> dict:
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


def build_admin(args) -> KafkaAdminClient:
    kwargs = {
        "bootstrap_servers": args.bootstrap_servers,
        "client_id": args.client_id,
        "request_timeout_ms": args.request_timeout_ms,
        "api_version_auto_timeout_ms": args.api_version_auto_timeout_ms,
    }

    if args.security_protocol:
        kwargs["security_protocol"] = args.security_protocol

    if args.sasl_mechanism:
        kwargs["sasl_mechanism"] = args.sasl_mechanism
    if args.sasl_plain_username:
        kwargs["sasl_plain_username"] = args.sasl_plain_username
    if args.sasl_plain_password:
        kwargs["sasl_plain_password"] = args.sasl_plain_password

    if args.ssl_cafile:
        kwargs["ssl_cafile"] = args.ssl_cafile
    if args.ssl_certfile:
        kwargs["ssl_certfile"] = args.ssl_certfile
    if args.ssl_keyfile:
        kwargs["ssl_keyfile"] = args.ssl_keyfile
    if args.ssl_password:
        kwargs["ssl_password"] = args.ssl_password
    if args.ssl_check_hostname is not None:
        kwargs["ssl_check_hostname"] = args.ssl_check_hostname

    return KafkaAdminClient(**kwargs)


def wait_until_topics_exist(admin: KafkaAdminClient, topics: List[str], timeout_s: int = 30, interval_s: float = 0.5) -> bool:
    end = time.time() + timeout_s
    remaining = set(topics)
    while time.time() < end:
        existing = set(admin.list_topics())
        remaining = set(t for t in remaining if t not in existing)
        if not remaining:
            return True
        time.sleep(interval_s)
    return False


